	static void dfs(int num, Set<Integer> res, int tmp) {
		if(tmp > num)
			return;
		if(!res.add(tmp))
			return;
		if( tmp%10 == 0) {
			dfs(num, res, tmp * 10 + 1);
		}else if(tmp%10 == 9) {
			dfs(num, res, tmp * 10 + 8);
		}else {
			dfs(num, res, tmp * 10 + tmp%10 - 1);
			dfs(num, res, tmp * 10 + tmp%10 + 1);
		}
	}

