class Solution:
    def generate(self, n: int):
        if n < 10:
            return [i for i in range(1, n+1)]

        level = 0
        num = n
        while num > 0:
            level += 1
            num //= 10

        queue = [i for i in range(1, 10)]
        res = queue[:]
        for _ in range(level-1):
            tmp = []
            for num in queue:
                tail = num%10
                for new_tail in [tail-1, tail+1]:
                    if 0 <= new_tail < 10:
                        new_num = num*10+new_tail
                        if new_num > n:
                            break
                        res.append(new_num)
                        tmp.append(new_num)
            queue = tmp

        return res

