public List<Integer> findJumpNumbers(int num) {
    List<Integer> result = new ArrayList<>();
    if (num < 0) {
        return result;
    }

    result.add(0);
    Deque<Integer> queue = new ArrayDeque<>();
    for (int i = 1; i < 10; i++) {
        queue.add(i);
    }

    bfs(queue, num, result);

    return result;
}

private void bfs(Deque<Integer> queue, int max, List<Integer> result) {
    while (!queue.isEmpty()) {
        int size = queue.size();
        for (int i = 0; i < size; i++) {
            int num = queue.poll();
            result.add(num);
            int lastDigit = num % 10;
            if (lastDigit == 0) {
                enqueue(num * 10 + 1, max, queue);
            } else if (lastDigit == 9) {
                enqueue(num * 10 + 8, max, queue);
            } else {
                enqueue(num * 10 + lastDigit - 1, max, queue);
                enqueue(num * 10 + lastDigit + 1, max, queue);
            }
        }
    }
}

private void enqueue(int num, int max, Deque<Integer> queue) {
    if (num <= max) {
        queue.offer(num);
    }
}
